47: /// @brief Caches the basic and JWT authentication tokens
48: class TokenCache {
49:  public:
50:   /// Construct authentication cache
51:   /// @param um UserManager singleton
52:   /// @param timeout default token expiration timeout
53:   explicit TokenCache(auth::UserManager* um, double timeout);
54:   ~TokenCache();
55: 
56:   struct Entry {
57:     friend class auth::TokenCache;
58: 
59:    public:
60:     explicit Entry(std::string username, bool a, double t)
61:         : _username(std::move(username)), _expiry(t), _authenticated(a) {}
62: 
63:     static Entry Unauthenticated() { return Entry("", false, 0); }
64:     static Entry Superuser() { return Entry("", true, 0); }
65: 
66:     std::string const& username() const noexcept { return _username; }
67:     bool authenticated() const noexcept { return _authenticated; }
68:     void authenticated(bool value) noexcept { _authenticated = value; }
69:     void setExpiry(double expiry) noexcept { _expiry = expiry; }
70:     double expiry() const noexcept { return _expiry; }
71:     bool expired() const noexcept;
72:     std::vector<std::string> const& allowedPaths() const {
73:       return _allowedPaths;
74:     }
75:     std::vector<std::string> const& roles() const { return _roles; }
76:     std::string const& jwtToken() const { return _jwtToken; }
77: 
78:    private:
79:     /// username
80:     std::string _username;
81:     // paths that are valid for this token
82:     std::vector<std::string> _allowedPaths;
83:     /// roles from JWT token
84:     std::vector<std::string> _roles;
85:     /// JWT token string
86:     std::string _jwtToken;
87:     /// expiration time (in seconds since epoch) of this entry
88:     double _expiry;
89:     /// User exists and password was checked
90:     bool _authenticated;
91:   };
92: 
93:  public:
94:   TokenCache::Entry checkAuthentication(rest::AuthenticationMethod authType,
95:                                         ServerState::Mode mode,
96:                                         std::string const& secret);
97: 
98:   /// Clear the cache of username / password auth
99:   void invalidateBasicCache();
100: 
101:   /// set new jwt secret(s), regenerate _jwtToken
102:   void setJwtSecrets(std::string active, std::vector<std::string> passive,
103:                      bool isES256);
104: 
105:   /// Get the jwt token, which should be used for communication
106:   std::string const& jwtToken() const noexcept;
107: 
108:   std::string jwtSecret() const;
109: 
110:  private:
111:   /// Check basic HTTP Authentication header
112:   TokenCache::Entry checkAuthenticationBasic(std::string const& secret);
113:   /// Check JWT token contents
114:   TokenCache::Entry checkAuthenticationJWT(std::string const& secret);
115:   /// Check JWT token contents and return full token string
116:   TokenCache::Entry checkAuthenticationJWT(std::string const& secret,
117:                                            std::string const& fullToken);
118: 
119:   bool validateJwtHeader(std::string_view headerWebBase64, bool& isES256);
120:   TokenCache::Entry validateJwtBody(std::string_view bodyWebBase64);
121:   bool validateJwtHMAC256Signature(std::string_view message,
122:                                    std::string_view signatureWebBase64);
123:   bool validateJwtES256Signature(std::string_view message,
124:                                  std::string_view signatureWebBase64);
125: 
126:   std::shared_ptr<velocypack::Builder> parseJson(std::string_view str,
127:                                                  char const* hint);
128: 
129:   /// generate new superuser jwtToken
130:   void generateSuperToken();
131: 
132:  private:
133:   auth::UserManager* const _userManager;
134: 
135:   mutable arangodb::basics::ReadWriteLock _basicLock;
136:   std::unordered_map<std::string, TokenCache::Entry> _basicCache;
137:   std::atomic<uint64_t> _basicCacheVersion{0};
138: 
139:   mutable arangodb::basics::ReadWriteLock _jwtSecretLock;
140: 
141:   std::vector<std::string> _jwtPassiveSecrets;
142:   std::string _jwtActiveSecret;
143:   bool _jwtActiveSecretIsES256{false};  /// true if active secret is ES256 key
144:   std::string _jwtSuperToken;           /// token for internal use
145: 
146:   mutable std::mutex _jwtCacheMutex;
147:   arangodb::basics::LruCache<std::string, TokenCache::Entry> _jwtCache;
148: 
149:   /// Timeout in seconds
150:   double const _authTimeout;
151: };
152: 
153: }  // namespace arangodb::auth
