36: namespace arangodb::auth {
37: 
38: // This class represents a 'user' entry.  It contains structures to
39: // store the access levels for databases and collections.  The user
40: // object must be serialized via `toVPackBuilder()` and written to the
41: // `_users` collection after modifying it.
42: 
43: class User {
44:   friend class UserManagerImpl;
45: 
46:  public:
47:   static User newUser(std::string const& user, std::string const& pass);
48:   static User fromDocument(velocypack::Slice const&);
49: 
50:  private:
51:   static void fromDocumentDatabases(auth::User&,
52:                                     velocypack::Slice const& databases,
53:                                     velocypack::Slice const& user);
54: 
55:  public:
56:   std::string const& key() const { return _key; }
57:   RevisionId rev() const { return _rev; }
58:   // updates the user's `_loaded` attribute
59:   void touch();
60: 
61:   std::string const& username() const { return _username; }
62:   std::string const& passwordMethod() const { return _passwordMethod; }
63:   std::string const& passwordSalt() const { return _passwordSalt; }
64:   std::string const& passwordHash() const { return _passwordHash; }
65:   bool isActive() const { return _active; }
66: 
67:   bool checkPassword(std::string const& password) const;
68:   void updatePassword(std::string const& password);
69:   bool checkAccessToken(std::string const& token) const;
70: 
71:   velocypack::Builder toVPackBuilder() const;
72: 
73:   void setActive(bool active) { _active = active; }
74: 
75:   // Grant specific access rights for db. The default "*" is also a
76:   // valid database name
77:   void grantDatabase(std::string const& dbname, auth::Level level);
78: 
79:   // Removes the entry, returns true if entry existed
80:   bool removeDatabase(std::string const& dbname);
81: 
82:   // Grant collection rights, "*" is a valid parameter for dbname and
83:   // collection.  The combination of "*"/"*" is automatically used for
84:   // the root
85:   void grantCollection(std::string const& dbname, std::string const& cname,
86:                        auth::Level level);
87: 
88:   // Removes the collection right, returns true if entry existed
89:   bool removeCollection(std::string const& dbname,
90:                         std::string const& collection);
91: 
92:   // Resolve the access level for this database.
93:   auth::Level configuredDBAuthLevel(std::string const& dbname) const;
94:   // Resolve rights for the specified collection.
95:   auth::Level configuredCollectionAuthLevel(std::string const& dbname,
96:                                             std::string const& cname) const;
97: 
98:   // Resolve the access level for this database. Might fall back to
99:   // the special '*' entry if the specific database is not found
100:   auth::Level databaseAuthLevel(std::string const& dbname) const;
101: 
102:   // Resolve rights for the specified collection. Falls back to the
103:   // special '*' entry if either the database or collection is not
104:   // found.
105:   auth::Level collectionAuthLevel(std::string const& dbname,
106:                                   std::string_view cname) const;
107: 
108:   // Content of `userData` fields
109:   velocypack::Slice userData() const { return _userData.slice(); }
110: 
111:   // Set content of `userData` fields
112:   void setUserData(velocypack::Builder&& b) { _userData = std::move(b); }
113: 
114:   // Content of internal `configData` field, used by the WebUI
115:   velocypack::Slice configData() const { return _configData.slice(); }
116: 
117:   // Set content of internal `configData` field, used by the WebUI
118:   void setConfigData(velocypack::Builder&& b) { _configData = std::move(b); }
119: 
120:   // Get all access tokens
121:   Result getAccessTokens(velocypack::Builder& builder) const;
122: 
123:   // Create an access token
124:   Result createAccessToken(std::string const& name, double validUntil,
125:                            velocypack::Builder& b);
126: 
127:   // Delete an access token
128:   Result deleteAccessToken(uint64_t id);
129: 
130:   // Time in seconds (since epoch) when user was loaded
131:   double loaded() const { return _loaded; }
132: 
133: #ifdef USE_ENTERPRISE
134:   std::set<std::string> const& roles() const { return _roles; }
135:   void setRoles(std::set<std::string> const& roles) { _roles = roles; }
136: #endif
137: 
138:  private:
139:   User(std::string&& key, RevisionId rid);
140: 
141:   typedef std::unordered_map<std::string, auth::Level,
142:                              arangodb::hash_monitored_string, std::equal_to<>>
143:       CollLevelMap;
144: 
145:   struct DBAuthContext {
146:     DBAuthContext(auth::Level dbLvl, CollLevelMap const& coll)
147:         : _databaseAuthLevel(dbLvl), _collectionAccess(coll) {}
148: 
149:     DBAuthContext(auth::Level dbLvl, CollLevelMap&& coll)
150:         : _databaseAuthLevel(dbLvl), _collectionAccess(std::move(coll)) {}
151: 
152:    public:
153:     auth::Level _databaseAuthLevel;
154:     CollLevelMap _collectionAccess;
155:   };
156: 
157:  private:
158:   std::string _key;
159:   RevisionId _rev;
160:   bool _active = true;
161: 
162:   std::string _username;
163:   std::string _passwordMethod;
164:   std::string _passwordSalt;
165:   std::string _passwordHash;
166:   std::unordered_map<std::string, DBAuthContext> _dbAccess;
167: 
168:   velocypack::Builder _userData;
169:   velocypack::Builder _configData;
170:   velocypack::Builder _accessTokens;
171: 
172:   // Time when user was loaded from DB
173:   double _loaded;
174: 
175: #ifdef USE_ENTERPRISE
176:   // @brief roles this user has
177:   std::set<std::string> _roles;
178: #endif
179: };
180: }  // namespace arangodb::auth
