962:                                                   ServerState::Mode mode) {
963:   bool found;
964:   std::string const& authStr = req.header(StaticStrings::Authorization, found);
965:   if (!found) {
966:     if (this->_auth->isActive()) {
967:       events::CredentialsMissing(req);
968:       return auth::TokenCache::Entry::Unauthenticated();
969:     }
970:     events::Authenticated(req, AuthenticationMethod::NONE);
971:     return auth::TokenCache::Entry::Superuser();
972:   }
973: 
974:   std::string::size_type methodPos = authStr.find(' ');
975:   if (methodPos == std::string::npos) {
976:     events::UnknownAuthenticationMethod(req);
977:     return auth::TokenCache::Entry::Unauthenticated();
978:   }
979: 
980:   // skip over authentication method and following whitespace
981:   char const* auth = authStr.c_str() + methodPos;
982:   while (*auth == ' ') {
983:     ++auth;
984:   }
985: 
986:   LOG_TOPIC_IF("c4536", DEBUG, arangodb::Logger::REQUESTS,
987:                Logger::logRequestParameters())
988:       << "\"authorization-header\",\"" << (void*)this
989:       << "\",SENSITIVE_DETAILS_HIDDEN";
990: 
991:   AuthenticationMethod authMethod = AuthenticationMethod::NONE;
992:   if (authStr.size() >= 6) {
993:     if (strncasecmp(authStr.c_str(), "basic ", 6) == 0) {
994:       authMethod = AuthenticationMethod::BASIC;
995:     } else if (strncasecmp(authStr.c_str(), "bearer ", 7) == 0) {
996:       authMethod = AuthenticationMethod::JWT;
997:     }
998:   }
999: 
1000:   req.setAuthenticationMethod(authMethod);
1001:   if (authMethod == AuthenticationMethod::NONE) {
1002:     events::UnknownAuthenticationMethod(req);
1003:     return auth::TokenCache::Entry::Unauthenticated();
1004:   }
1005: 
1006:   if (authMethod != AuthenticationMethod::JWT &&
1007:       mode == ServerState::Mode::STARTUP) {
1008:     // during startup, the normal authentication is not available
1009:     // yet. so we have to refuse all requests that do not use
1010:     // a JWT.
1011:     // do not audit-log anything in this case, because there is
1012:     // nothing we can do to verify the credentials.
1013:     return auth::TokenCache::Entry::Unauthenticated();
1014:   }
1015: 
1016:   auto authToken =
1017:       this->_auth->tokenCache().checkAuthentication(authMethod, mode, auth);
1018:   req.setAuthenticated(authToken.authenticated());
1019:   req.setTokenExpiry(authToken.expiry());
1020:   req.setUser(authToken.username());  // do copy here, so that we do not
1021:   // invalidate the member
1022:   req.setRoles(authToken.roles());
1023:   req.setJwtToken(authToken.jwtToken());
1024:   if (authToken.authenticated()) {
1025:     events::Authenticated(req, authMethod);
1026:   } else {
1027:     events::CredentialsBad(req, authMethod);
1028:   }
1029:   return authToken;
1030: }
